public class SwitchExpr {
    public static void main(String[] args) {
        for (int day = 1; day <= 4; day++) {
            String name = switch (day) {
                case 1 -> "Mon";
                case 2 -> "Tue";
                case 3 -> "Wed";
                default -> "Other";
            };
            System.out.println(name);
        }
    }
}
